#include <bits/stdc++.h>
using namespace std;
int main(){
    string a;
    int sum=0,s[27];
    getline(cin,a);
    for(int i=1;i<=15;i++)s[i]=((i-1)%3)+1;
    for(int i=16;i<=19;i++)s[i]=i-15;
    for(int i=20;i<=22;i++)s[i]=i-19;
    for(int i=23;i<=26;i++)s[i]=i-22;
    for(int i=0;i<a.size();i++){
        if(a[i]==' ')sum++;
        else if(a[i]>='a' && a[i]<='z')sum+=s[a[i]-'a'+1];
    }
    cout<<sum;
    return 0;
}
